import React, {Component} from 'react';

import { CustBarraSuperior } from '../../assets/Customizacoes';


import * as FaIcons from "react-icons/fa";
import { Link } from 'react-router-dom';
const FaBars = <FaIcons.FaBars size = {40} />
const FaTimes = <FaIcons.FaTimes size = {40}/>



const BotaoBarraLateral = () => {
    return(
        <span>
            {CustBarraSuperior.logo}
        </span>
    );
}


const CampoTitulo = () => {

    return(
        <div id='campoTitulo' href="/"  >
            <img
                alt=""
                src={CustBarraSuperior.logo}
                width="40"
                height="40"
                className="d-inline-block"
            />{' '}                
            {CustBarraSuperior.titulo}
        </div>        
    );
}

const NomeUsuario = () => {
    return(
        <div>
           Usuário
        </div>
    );
}

const CampoDropDown = () => {
    return(
        <select title='Opções'>
            <option href='#item'>teste</option>
            <option href='#item'>teste</option>
            <hr />
            <option href='#item'>teste</option>
        </select>
    );
}

const CampoSair = () => {
    return(
        <Link to='/'>
            Sair
        </Link>
    );
}

function BarraSuperior(){
    return(
        <div id='barraSuperior' expand='lg'>
            <div id='opcoesFixas' className='divsBarraSuperior'>
                
                <CampoTitulo />
            </div>
            <div id='opcoesColapsaveis' className='divsBarraSuperior justify-content-end'>
                <div className='me-auto'>
                    <NomeUsuario />
                    <CampoDropDown />
                    <CampoSair />
                </div>                    
            </div>    
        </div>
    );
}


export default BarraSuperior;
